type":"slug","current":"superteam-community-launchpad"},"teamMembers":null,"techStack":["Solana","Anchor","React","TypeScript","Token"],"textOne":null,"textThree":null,"textTwo":null,"theChallenge":[{"_key":"1","_type":"block","children":[{"_key":"1a","_type":"span","text":"Superteam DAO needed a secure, scalable Web3 solution that could handle high traffic while providing a seamless user experience. The challenge was to build on Solana with optimal performance and minimal gas costs."}],"markDefs":[],"style":"normal"}],"theSolution":[{"_key":"default","_type":"block","children":[{"_key":"1","_type":"span","text":"Successfully delivered the project with all requested features."}],"markDefs":[],"style":"normal"}],"title":"Superteam Community Launchpad","valueDelivered":null},{"_createdAt":"2023-10-10T23:11:34Z","_id":"7f626c78-5c89-4a0b-9bd6-ab6e11fa3bd1","_updatedAt":"2026-02-17T08:25:27Z","additionalImages":[{"_key":"3cd1642f9747","_type":"image","asset":{"_ref":"image-3cc79cc0015c357a0e600b49df1c1ac297c851ec-3186x2056-png","_type":"reference"}}],"awards":null,"body":[{"_key":"auto-7f626c78","_type":"block","children":[{"_key":"auto-span-7f626c78","_type":"span","text":"Earn as you progress, level by level. Plunder bustling cities, raid lucrative docks, and steer clear of prison or the perils of mutiny."}],"markDefs":[],"style":"normal"}],"categories":[{"_id":"f93d7d19-c335-4067-a92d-97037f424e4b","description":null,"title":"Gaming"},{"_id":"f39b5424-a1ab-481e-bc32-9f9e85e05609","description":null,"title":"Blockchain Integrated Apps"}],"challengeLevel":null,"clientAuthor":"Emploice","clientAuthorRole":"Founder & CEO","clientImage":{"_type":"image","asset":{"_ref":"image-2552fd56d656f630eb6d0402c893db54dcf3babb-356x106-png","_type":"reference"},"crop":{"_type":"sanity.imageCrop","bottom":0,"left":0.032534246575342464,"right":0.6815068493150682,"top":0},"hotspot":{"_type":"sanity.imageHotspot","height":1,"width":0.28595890410958935,"x":0.17551369863013713,"y":0.5}},"clientName":"Reavers","clientTestimonial":"The communication and time efficiency was perfect. I was most impressed by their ability to understand us and stay on brief.","demoVideo":null,"description":"Earn as you progress, level by level. Plunder bustling cities, raid lucrative docks, and steer clear of prison or the perils of mutiny.","githubLink":"https://x.com/TheSevenSeas_io","headingOne":null,"headingThree":null,"headingTwo":null,"isFeatured":true,"keyFeatures":null,"liveSiteLink":"https://www.thesevenseas.io/","mainImage":{"_type":"image","asset":{"_ref":"image-e62f7665f7e6c94b0454c3525485763efe982a33-1601x901-png","_type":"reference"}},"mockupImage":{"_type":"image","asset":{"_ref":"image-e99a7f4dde9eac2c07c5c1237cfec83adf48877a-1601x901-png","_type":"reference"}},"projectDuration":9,"projectMetrics":"Built for Reavers, this Web3 Application solution handles thousands of daily active users with sub-second transaction finality on Solana.","projectStatus":null,"projectTimeline":null,"projectType":"Web3 Application","publishedAt":"2023-09-27T23:08:00.000Z","relatedProjects":null,"servicesProvided":null,"slug":{"_type":"slug","current":"reavers-nft-idle-game"},"teamMembers":null,"techStack":["Solana","Next.js","TypeScript","Web3.js","TailwindCSS"],"textOne":null,"textThree":null,"textTwo":null,"theChallenge":[{"_key":"1","_type":"block","children":[{"_key":"1a","_type":"span","text":"Reavers needed a secure, scalable Web3 solution that could handle high traffic while providing a seamless user experience. The challenge was to build on Solana with optimal performance and minimal gas costs."}],"markDefs":[],"style":"normal"}],"theSolution":[{"_key":"4d00e811cb68","_type":"block","children":[{"_key":"f4a329afe7210","_type":"span","marks":[],"text":"We delivered a complex and comprehensive technical infrastructure for Reavers that created one of the most successful NFT idle games on Solana. With more than 8 months of development, we built a system that put fun first and was blockchain enhanced without hindering the gameplay experience. Here is the breakdown of the core characteristics:"}],"markDefs":[],"style":"normal"},{"_key":"c91563d3928f","_type":"block","children":[{"_key":"c6710a58a4ea0","_type":"span","marks":[],"text":"\n"},{"_key":"6888e259b67f0","_type":"span","marks":["strong"],"text":"Full On-Chain Game Architecture: "},{"_key":"e075e2a538f2","_type":"span","marks":[],"text":"We developed complex Solana programs handling the entire game state transparently on-chain like NFT-based character progression with dynamic "Marking" mechanics and flanking bonuses, the innovative War Spoils resource system which was a unique economy functioning like a secondary currency for diplomacy manipulation, trading, unit capturing and cannon purchasses, raid mechanics, city plundering, dock raids, prison escapes and mutiny events with real risk to reward balance. All game logic was executed on-chain with sub-second finality for highly responsive gameplay."}],"markDefs":[],"style":"normal"},{"_key":"c81f899b897a","_type":"block","children":[{"_key":"f9170cd452d40","_type":"span","marks":[],"text":""}],"markDefs":[],"style":"normal"},{"_key":"2f9cb84b83e9","_type":"block","children":[{"_key":"abb04743d5da","_type":"span","marks":["strong"],"text":"Scalable Idle Mechanics:"},{"_key":"4e84b2c96257","_type":"span","marks":[],"text":" We built the architecture in a way that enabled real "play as you want" adaptability with the background progression systems calculating rewards based on elapsed time, on-chain staking mechanisms for resource accumulation, automated event triggers allowing both passive and active gameplay styles and carefully balanced early game weakness (no traditional tank or ranged units) that required strategic tome selection and unit composition.\n\n"},{"_key":"aefedb746a2a","_type":"span","marks":["strong"],"text":"Advanced NFT and Progression Systems:"},{"_key":"99add94d1f87","_type":"span","marks":[],"text":" Here we included dynamic NFT metadata that was updating based on in-game actions and achievements, "Marking" enemy mechanics with flanking bonus scalability, society trait systems (Chaos/Materium routes) affecting playstyle and unit effectiveness, integration with Magic Eden marketplace for seamless NFT trading. Reavers reached top seller status on Magic Eden proving market fit.\n\n"},{"_key":"26d38aec6354","_type":"span","marks":["strong"],"text":"TypeScript and Rust Development:"},{"_key":"708099fb5015","_type":"span","marks":[],"text":" Our implementation provided type-safe interactions between Solana programs and frontend, Rust based smart contracts for secure and gas optimized on-chain logic, client side game logic mirroring on-chain validation for instant feedback and real-time state synchronization between blockchain and game UI.\n\n"},{"_key":"64ad15a606ba","_type":"span","marks":["strong"],"text":"Performance and Optimization:"},{"_key":"c4872b216d55","_type":"span","marks":[],"text":" We worked on efficient account structures using Solana's Program Derived Addresses (PDAs), we optimized rent management reducing long-term costs, batched transaction processing where beneficial and implemented client side prediction with on-chain verification for responsive gameplay.\n\n"},{"_key":"2f689d1bc634","_type":"span","marks":["strong"],"text":"Backend and Frontend Integration:"},{"_key":"4523c2a7c0e2","_type":"span","marks":[],"text":" Besides smart contracts, we also built backend systems for off-chain data catching and query optimization, fixed frontend bugs and improve UX flows, created admin tooling for game management and integrated wallet systems (Phantom, Solflare) seamlessly.\n\n"},{"_key":"897b46599bd4","_type":"span","marks":["strong"],"text":"Community Features:"},{"_key":"5f5d4cfea745","_type":"span","marks":[],"text":" Created on-chain systems enabling transparent leaderboards and achievement tracking, fair reward distribution fully verifiable, diplomacy mechanics where players form alliances (critical given Reavers benefit from figthing players/free cities). Reavers community reached more than 25000 members and was built around shared ownership and transparent game mechanics.\n\n"},{"_key":"529c08d9be4f","_type":"span","marks":["strong"],"text":"Sustainable Game Economy:"},{"_key":"6ec597c44c3e","_type":"span","marks":[],"text":" THe game economy was designed to avoid pay-to-earn pitfalls and included balanced resource sinks (War Spoils system) and faucets, real utility for game mechanics, strategic depth in tome selection (Rock, Alchemy; Horde; Warding; Beasts) for unit composition and multiple viable build paths (Chaos Chosen Destroyers, Materium Runesmiths, and others)\n\nAs a result, Reavers became a top seller on Magic Eden and built a community of more that 25000 members. THe 8 month development period produced a game that actually respected player's time regardless if they played 5 minutes or 5 hours daily. All of this while demonstrating that blockchain games could be fun first, have Web3 transparency, true ownership and community governance rather than detracting from the experience.\n"}],"markDefs":[],"style":"normal"},{"_key":"cda2105f46dc","_type":"block","children":[{"_key":"65a852757c2e0","_type":"span","marks":[],"text":"\n"}],"markDefs":[],"style":"normal"}],"title":"Reavers - Plunder, Raid, Navigate.","valueDelivered":null},{"_createdAt":"2023-08-11T10:32:05Z","_id":"fa2c6f0b-7150-49f9-8fe8-f7258db5a0d7","_updatedAt":"2026-02-17T08:25:36Z","additionalImages":null,"awards":null,"body":[{"_key":"auto-fa2c6f0b","_type":"block","children":[{"_key":"auto-span-fa2c6f0b","_type":"span","text":"We built Hashling's outstanding mint and staking experience as an xNFT."}],"markDefs":[],"style":"normal"}],"categories":[{"_id":"f93d7d19-c335-4067-a92d-97037f424e4b","description":null,"title":"Gaming"}],"challengeLevel":null,"clientAuthor":"ASICs (Josh)","clientAuthorRole":"Founder","clientImage":{"_type":"image","asset":{